"""Reality signal computation from search results."""

from __future__ import annotations

from datetime import date, datetime, timedelta

_FUNDING_KEYWORDS = frozenset([
    "ycombinator",
    "y combinator",
    "yc w",
    "yc s",
    "backed by",
    "funded by",
    "raised",
    "series a",
    "series b",
    "series c",
    "sequoia",
    "a16z",
    "andreessen",
    "venture",
    "acquired",
])


def _parse_date(date_str: str) -> date | None:
    """Parse a YYYY-MM-DD date string, returning None on failure."""
    try:
        return datetime.strptime(date_str[:10], "%Y-%m-%d").date()
    except (ValueError, TypeError):
        return None


def _recency_score(repos: list[dict], hn_posts: list[dict], today: date) -> int:
    """Compute recency score (0-10): recent activity scores higher.

    Measures what fraction of items were updated within the last 365 days.
    >= 50% recent → 10, >= 25% recent → 5, otherwise → 0.
    """
    dates: list[date] = []
    for r in repos:
        d = _parse_date(r.get("updated", ""))
        if d:
            dates.append(d)
    for h in hn_posts:
        d = _parse_date(h.get("date", ""))
        if d:
            dates.append(d)

    if not dates:
        return 0

    cutoff = today - timedelta(days=365)
    recent_count = sum(1 for d in dates if d >= cutoff)
    fraction = recent_count / len(dates)

    if fraction >= 0.5:
        return 10
    if fraction >= 0.25:
        return 5
    return 0


def _funding_score(repos: list[dict]) -> int:
    """Compute funding signal score (0-5) from GitHub repo descriptions.

    Returns 5 if any repo description contains a known funding keyword.
    """
    for r in repos:
        desc = (r.get("description") or "").lower()
        if any(kw in desc for kw in _FUNDING_KEYWORDS):
            return 5
    return 0


def _velocity_score(repos: list[dict], hn_posts: list[dict], today: date) -> int:
    """Compute community velocity score (0-5): growing community scores higher.

    Compares items updated in the last 6 months (recent) to items updated
    6–24 months ago (older).
    growing (recent >= older) → 5, partial activity → 2, stagnant → 0.
    """
    cutoff_recent = today - timedelta(days=180)
    cutoff_older = today - timedelta(days=730)

    recent = 0
    older = 0

    all_dates = [_parse_date(r.get("updated", "")) for r in repos] + [
        _parse_date(h.get("date", "")) for h in hn_posts
    ]

    for d in all_dates:
        if d is None:
            continue
        if d >= cutoff_recent:
            recent += 1
        elif d >= cutoff_older:
            older += 1

    if recent == 0 and older == 0:
        return 0
    if recent >= older:
        return 5
    if recent > 0:
        return 2
    return 0


def compute_signal(
    repos: list[dict],
    hn_posts: list[dict],
    top_similarity: float | None = None,
    today: date | None = None,
) -> dict:
    """Compute a 0-100 reality signal from search results.

    Args:
        repos: GitHub repository results.
        hn_posts: Hacker News post results.
        top_similarity: Optional average cosine similarity of the top results
            to the query embedding (0–1). When provided, a semantic boost
            component is added to the breakdown and score.
        today: Reference date for recency/velocity calculations. Defaults to
            today's date. Pass a fixed date in tests for determinism.

    Returns:
        Dict with ``score``, ``verdict``, and ``breakdown``.
        Breakdown always includes: github, hn, recency, funding, velocity.
        Breakdown includes ``semantic`` only when top_similarity is provided.
    """
    if today is None:
        today = date.today()

    # GitHub component (0-40): repo count × star quality
    total_repos = len(repos)
    max_stars = max((r["stars"] for r in repos), default=0)

    if total_repos == 0:
        gh_score = 0
    elif total_repos <= 3:
        gh_score = 10
    elif total_repos <= 7:
        gh_score = 20
    else:
        gh_score = 30

    if max_stars >= 5000:
        gh_score = min(40, gh_score + 10)
    elif max_stars >= 1000:
        gh_score = min(40, gh_score + 8)
    elif max_stars >= 100:
        gh_score = min(40, gh_score + 5)

    # HN component (0-25): post count × point quality
    total_hn = len(hn_posts)
    max_points = max((p["points"] for p in hn_posts), default=0)

    if total_hn == 0:
        hn_score = 0
    elif total_hn <= 2:
        hn_score = 7
    else:
        hn_score = 15

    if max_points >= 100:
        hn_score = min(25, hn_score + 10)
    elif max_points >= 30:
        hn_score = min(25, hn_score + 6)

    # Semantic component (0-15): rewards conceptually similar results
    semantic_score = 0
    if top_similarity is not None:
        if top_similarity >= 0.8:
            semantic_score = 15
        elif top_similarity >= 0.6:
            semantic_score = 10
        elif top_similarity >= 0.4:
            semantic_score = 7
        elif top_similarity >= 0.2:
            semantic_score = 3

    # Recency component (0-10): recent activity scores higher
    recency_score = _recency_score(repos, hn_posts, today)

    # Funding component (0-5): commercial backing signals
    funding_score = _funding_score(repos)

    # Velocity component (0-5): growing community scores higher
    velocity_score = _velocity_score(repos, hn_posts, today)

    score = min(
        100,
        gh_score + hn_score + semantic_score + recency_score + funding_score + velocity_score,
    )

    if score < 30:
        verdict = "LOW"
    elif score <= 60:
        verdict = "MODERATE"
    else:
        verdict = "HIGH"

    breakdown: dict[str, int] = {
        "github": gh_score,
        "hn": hn_score,
        "recency": recency_score,
        "funding": funding_score,
        "velocity": velocity_score,
    }
    if top_similarity is not None:
        breakdown["semantic"] = semantic_score

    return {
        "score": score,
        "verdict": verdict,
        "breakdown": breakdown,
    }

